// 第1层检测：硬编码规则（快速过滤）
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;
  const checks = {
    range_check: true,
    completeness_check: true,
    timestamp_check: true,
    errors: [],
    need_llm: false
  };

  // 数值范围检查
  if (data.temperature !== undefined) {
    if (data.temperature < -50 || data.temperature > 200) {
      checks.range_check = false;
      checks.errors.push({
        type: 'range',
        field: 'temperature',
        value: data.temperature,
        message: '温度超出正常范围 (-50~200°C)'
      });
    }
  }

  // 必填字段检查
  const requiredFields = ['deviceId', 'timestamp'];
  for (const field of requiredFields) {
    if (!data[field]) {
      checks.completeness_check = false;
      checks.errors.push({
        type: 'completeness',
        field: field,
        message: `缺少必填字段: ${field}`
      });
    }
  }

  // 时间戳有效性检查
  if (data.timestamp) {
    const timestamp = new Date(data.timestamp).getTime();
    const now = Date.now();
    if (timestamp > now) {
      checks.timestamp_check = false;
      checks.errors.push({
        type: 'timestamp',
        field: 'timestamp',
        value: data.timestamp,
        message: '时间戳在未来'
      });
    }
  }

  // 判断是否需要LLM进一步检测
  // 逻辑矛盾等复杂情况需要LLM
  if (data.status === '运行中' && data.power === 0) {
    checks.need_llm = true;
    checks.errors.push({
      type: 'logic',
      fields: ['status', 'power'],
      message: '可能存在逻辑矛盾：状态为运行中但功率为0',
      severity: 'medium'
    });
  }

  results.push({
    json: {
      ...data,
      _layer1_checks: checks,
      _passed_layer1: checks.range_check && checks.completeness_check && checks.timestamp_check
    }
  });
}

return results;

// 第3层检测：LLM异常检测（模拟）
const items = $input.all();
const results = [];

for (const item of items) {
  const data = item.json;

  // 模拟LLM分析
  const llmAnalysis = {
    is_anomaly: false,
    anomaly_type: 'none',
    severity: 'none',
    reasons: [],
    evidence: [],
    suggestion: '数据正常',
    confidence: 0.85
  };

  // 检测逻辑矛盾
  if (data.status === '运行中' && data.power === 0) {
    llmAnalysis.is_anomaly = true;
    llmAnalysis.anomaly_type = 'logic';
    llmAnalysis.severity = 'medium';
    llmAnalysis.reasons = [
      '设备状态显示运行中，但功率为0',
      '可能是传感器故障或设备进入待机模式'
    ];
    llmAnalysis.evidence = [
      'status=运行中',
      'power=0'
    ];
    llmAnalysis.suggestion = '建议检查设备传感器状态，或确认设备是否处于特殊运行模式';
    llmAnalysis.confidence = 0.75;
  }

  results.push({
    json: {
      ...data,
      _llm_analysis: llmAnalysis,
      _final_status: llmAnalysis.is_anomaly ? 'anomaly_detected' : 'normal'
    }
  });
}

return results;

// 直接标记为正常（规则已明确）
const items = $input.all();
const results = [];

for (const item of items) {
  results.push({
    json: {
      ...item.json,
      _final_status: 'normal',
      _processing_method: 'rule-based',
      _llm_analysis: {
        is_anomaly: false,
        anomaly_type: 'none',
        severity: 'none',
        confidence: 1.0
      }
    }
  });
}

return results;

// 异常分级处理
const items = $input.all();
const highRisk = [];
const mediumRisk = [];
const lowRisk = [];

for (const item of items) {
  const severity = item.json._llm_analysis?.severity || item.json._layer1_checks?.errors?.[0]?.severity || 'low';

  const alertData = {
    json: {
      alert_id: `alert-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`,
      severity: severity,
      data: item.json,
      anomaly_info: item.json._llm_analysis || item.json._layer1_checks,
      created_at: new Date().toISOString(),
      requires_immediate_action: severity === 'high'
    }
  };

  if (severity === 'high') {
    highRisk.push(alertData);
  } else if (severity === 'medium') {
    mediumRisk.push(alertData);
  } else {
    lowRisk.push(alertData);
  }
}

return [highRisk, mediumRisk, lowRisk];

// 高风险异常 - 立即告警
const items = $input.all();
const results = [];

for (const item of items) {
  results.push({
    json: {
      alert_sent: true,
      channel: 'urgent',
      message: `【紧急】检测到高风险异常: ${item.json.anomaly_info?.reasons?.[0] || '数据异常'}`,
      data: item.json,
      sent_at: new Date().toISOString()
    }
  });

  console.log(`🚨 高风险告警: ${item.json.alert_id}`);
}

return results;

// 中风险异常 - 记录日志
