}

return results;

// 明确异常数据处理
const items = $input.all();
const results = [];

for (const item of items) {
  const errors = item.json._layer1_checks?.errors || [];
  results.push({
    json: {
      status: 'rejected',
      errors: errors,
      data: item.json,
      rejected_at: new Date().toISOString()
    }
  });
}

return results;
